  "verses": [
    {
      "n": 14,
      "column": "left",
      "text": "Un winna Dseṙṙams-Up-\npuris laid irr weens puḟs Ins/pee\nweena Wehricha/ un ta trescha\nTeesa no weena Inna Wiḣna\npee weena Auna/ un tweens Inna\nZettortnis pee weena Jehra.Schis\nirr tas Dedsains-Uppurß ikatrâ\njaunâ Mehneti / pehz ta Gadda\nMehnescheem.\n"
    },
    {
      "n": 15,
      "column": "left",
      "text": "Un weens Ahśis lai tatai-\nfihtß tohp par Grehku-Uppuri\ntam KUNGAM / pahri pahr to\nnemittejamu Dedsamu-Uppuri\nlihds ar weenu Dserxamu-Up-\npuri.\n"
    },
    {
      "n": 16,
      "column": "left",
      "text": "Un pirma Mehnefi / zet-\ntortäpadefinita Deenâ irr tee\nPasta-Swehtki tam KUNGAM.\n"
    },
    {
      "n": 17,
      "column": "left",
      "text": "Un peektäpadefinita Dee-\nnâ/ ta paścha Mehnes/ irr tee\nSwehtki : feptix Deenas buhs\nneraudsetas Maises ehst.\n"
    },
    {
      "n": 18,
      "column": "left",
      "text": "Pirma Deena laid irr wee-\nna twehta Safaukschana/ nekah-\ndu Kalposchanas Darbu buhs\njums darriht.\n"
    },
    {
      "n": 19,
      "column": "left",
      "text": "Bet jums buhs weenu\nUgguni par Dedsamu-Uppuri\ntam KUNGAM uppureht/ di-\nwi Wehrfenus no leelem Loh-\npeem/ un weenu Aunu/ ir feptix\ngadskahrtigus Zehrus / kas bes\nWainas.\n"
    },
    {
      "n": 20,
      "column": "left",
      "text": "Un winnu Ehdamo-Up-\npurs laid irr Kweefchu-Milti/kas\nar Etji fajankti / trihs Definiti\npee weena Wehrfena/ un pee wee-\nna Auna buhs jums diwi Def-\ninitus fataifiht.\n"
    },
    {
      "n": 21,
      "column": "left",
      "text": "Weenu Definitu buhs tew\n"
    },
    {
      "n": 22,
      "column": "right",
      "text": "Pehz to weenu Ahśi par\nGrehku-Uppuri/par Salihdsina-\nschanu par jums.\n"
    },
    {
      "n": 23,
      "column": "right",
      "text": "Pahri pahr to Rihta-Up-\npuri/ kas par to nemittejamu\nDedsamu-Uppuri irr/buhs jums\nschahß Leetas fataifiht.\n"
    },
    {
      "n": 24,
      "column": "right",
      "text": "Un ta buhs jums ikdeenas/\nfeptix Deenas ta Ugguns (Up-\npura) Maisi fataifiht/ par faldut\nSmarschu tam KUNGAM/\npahri pahr to nemittejamu De-\ndsamu-Uppuri buhs tam fataifi-\ntam tapt/ lihds ar winna Dser-\nxamu-Uppuri.\n"
    },
    {
      "n": 25,
      "column": "right",
      "text": "Un feptitâ Deenâ laid\njums weena twehta Safaukscha-\nna irr/ nekahdu Kalposchanas-\nDarbu buhs jums darriht.\n"
    },
    {
      "n": 26,
      "column": "right",
      "text": "Un tai Deenâ to Pirma-\nju/ kad juhs weenu jaunu Ehda-\nmu-Uppuri tam KUNGAM up-\npurejat/ pehz juhsu Neddetahin/\nlaid jums weena twehta Safauk-\nschana irr/ nekahdu Kalposcha-\nnas-Darbu buhs jums darriht.\n"
    },
    {
      "n": 27,
      "column": "right",
      "text": "Tad buhs jums tam\nKUNGAM weenu Dedsamu-\nUppuri par faldut Smarschu up-\npureht/ diwi Wehrfenus no lee-\nleem Lohpeem/ weenu Aunu/\nfeptix gadskahrtigus Zehrus.\n"
    },
    {
      "n": 28,
      "column": "right",
      "text": "Un winnu Ehdainu-Up-\npuri no Kweefchu-Milteem ar\nEtji fajaukteem/ trihs Defini-\ntus pee weena Wehrfcha / diwi\nDefinitus pee weena Auna.\n"
    },
    {
      "n": 29,
      "column": "right",
      "text": "Weenu Definitu pee wee-\n"
    }
  ],
  "confidence": "high",
  "notes": ""
}
